import axios from "axios";

const BASE_URL = "http://localhost:5000";

export async function recognizeText(imageFile) {
  const formData = new FormData();
  formData.append("file", imageFile);

  const response = await axios.post(`${BASE_URL}/predict`, formData, {
    headers: { "Content-Type": "multipart/form-data" },
    timeout: 30000,
  });

  return response.data;
}

export async function healthCheck() {
  const response = await axios.get(`${BASE_URL}/health`, { timeout: 5000 });
  return response.data;
}

/* Mock result — used when Flask backend is not running */
export function getMockResult() {
  return new Promise((resolve) =>
    setTimeout(() => {
      resolve({
        text: "ආයුබෝවන් ශ්‍රී ලංකා",
        characters: [
          { char: "ආ", confidence: 0.97 },
          { char: "යු", confidence: 0.91 },
          { char: "බෝ", confidence: 0.88 },
          { char: "ව", confidence: 0.95 },
          { char: "න්", confidence: 0.82 },
          { char: "ශ්‍රී", confidence: 0.79 },
          { char: "ල", confidence: 0.93 },
          { char: "ං", confidence: 0.86 },
          { char: "කා", confidence: 0.90 },
        ],
        processing_time_ms: 342,
      });
    }, 1800)
  );
}
